INSERT INTO `forum_posts` (`id`, `user_id`, `category_id`, `title`, `content`, `image_url`, `image_alt`, `image_source`, `status`, `admin_note`, `views`, `likes`, `comments_count`, `is_pinned`, `is_locked`, `is_deleted`, `created_at`, `updated_at`) VALUES
(1, 1, 2, 'Cara Menanam Cabai Rawit di Polybag untuk Pemula', 'Menanam cabai rawit di polybag sangat cocok untuk lahan terbatas. Berikut panduan lengkapnya:\n\n1. Siapkan polybag ukuran 30x30cm\n2. Campur tanah, kompos, dan sekam (2:1:1)\n3. Pilih bibit unggul atau semai sendiri\n4. Tanam dengan hati-hati\n5. Siram 2x sehari\n6. Beri pupuk NPK setiap 2 minggu\n\nTips: Letakkan di tempat yang mendapat sinar matahari minimal 6 jam sehari.', NULL, NULL, NULL, 'Approved', NULL, 174, 33, 8, 1, 0, 0, '2026-04-17 06:58:32', '2026-06-16 02:23:00'),
(2, 2, 3, 'Panduan Lengkap Budidaya Padi Sistem Jajar Legowo', 'Sistem jajar legowo meningkatkan hasil panen padi hingga 20%. Berikut implementasinya:\n\n📋 Persiapan Lahan:\n- Olah tanah hingga gembur\n- Buat saluran irigasi yang baik\n\n🌱 Penanaman:\n- Gunakan jarak tanam 2:1 atau 4:1\n- Kedalaman tanam 2-3 cm\n\n💧 Pengelolaan Air:\n- Genangi 2-3 cm saat tanam\n- Keringkan saat anakan maksimal', NULL, NULL, NULL, 'Approved', NULL, 97, 15, 4, 0, 0, 0, '2026-04-17 06:58:32', '2026-04-20 12:35:26'),
(3, 3, 4, '7 Varietas Tomat Cherry yang Cocok untuk Iklim Tropis', 'Tomat cherry semakin populer! Berikut varietas yang terbukti adaptif di Indonesia:\n\n🍅 **Sweet 100**\n- Rasa manis, tahan penyakit\n- Panen: 70-80 hari\n\n🍅 **Sungold**\n- Warna oranye, rasa tropis\n- Tahan panas\n\n🍅 **Red Robin**\n- Kompak, cocok untuk pot\n- Buah lebat', NULL, NULL, NULL, 'Approved', NULL, 215, 42, 13, 0, 0, 0, '2026-04-17 06:58:32', '2026-04-20 13:56:11'),
(4, 2, 1, 'Pengalaman Pertama Ikut Komunitas Tani Online', 'Halo teman-teman! Saya baru bergabung minggu lalu dan sangat terbantu dengan diskusi di sini. Kemarin saya tanya tentang hama wereng, dan dalam 1 jam sudah dapat 5 solusi berbeda!\n\nYang saya suka:\n✅ Jawaban praktis dari petani berpengalaman\n✅ Bisa share foto langsung\n✅ Admin responsif\n\nTerima kasih sudah menerima saya! 🙏', NULL, NULL, NULL, 'Approved', NULL, 45, 12, 6, 0, 0, 0, '2026-04-17 06:58:32', '2026-04-17 06:58:32'),
(5, 1, 5, 'Tips Memilih Bibit Ayam Kampung Unggul', 'Memilih bibit ayam kampung yang unggul sangat penting untuk hasil maksimal. Berikut ciri-cirinya:\n\n1. Gerakan aktif dan lincah\n2. Bulu bersih dan mengkilap\n3. Mata cerah tidak berair\n4. Nafsu makan baik\n5. Berat badan ideal sesuai umur\n\nHarga bibit berkualitas biasanya Rp 15.000-25.000 per ekor.', NULL, NULL, NULL, 'Approved', NULL, 89, 9, 3, 0, 0, 0, '2026-04-17 06:58:32', '2026-04-20 12:37:27'),
(7, 1, 2, 'test', 'coba aja si', NULL, NULL, NULL, 'Approved', NULL, 0, 3, 0, 0, 0, 0, '2026-05-01 20:10:40', '2026-05-01 21:07:09'),
(8, 1, 1, 'tes', 'rs', NULL, NULL, NULL, 'Rejected', NULL, 0, 0, 0, 0, 0, 0, '2026-06-01 02:15:14', '2026-06-01 02:15:51'),
(9, 1, 3, 'bawang merah probolinggo', 'saya cari bawang /komoditas', NULL, NULL, NULL, 'Approved', 'disetujui', 0, 0, 0, 0, 0, 0, '2026-06-18 07:04:42', '2026-06-18 07:05:15');
